    int front = 0, rear = 0;
    queue[rear++] = root;

    while (front < rear) {
        int levelSize = rear - front;
        int levelValues[MAX_NODES];
        int levelIndex = 0;

        for (int i = 0; i < levelSize; i++) {
            struct Node* node = queue[front++];

            if (node->left != NULL) {
                queue[rear++] = node->left;
            }
            if (node->right != NULL) {
                queue[rear++] = node->right;
